        # Take main part before /
        main_part = str(cpc_code).split('/')[0]
        # Remove any trailing non-alphanumeric
        clean_part = re.sub(r'[^A-Z0-9]$', '', main_part)
        return clean_part
    except:
        return None

# Process patents
