args.code:
import json, re

cpc_monthly_counts = {}
for p in var_functions.query_db:44:
    grant_date = p.get('grant_date', '')
    if not grant_date or not any(m in grant_date.lower() for m in ['jul','aug','sep','oct','nov','dec']):
        continue
    try:
        for item in json.loads(p.get('cpc', '[]')):
            code = item.get('code')
            if code:
                level_4 = re.sub(r'[^A-Z0-9]$', '', str(code).split('/')[0])
                if level_4:
                    if level_4 not in cpc_monthly_counts:
                        cpc_monthly_counts[level_4] = {}
                    cpc_monthly_counts[level_4]['total'] = cpc_monthly_counts[level_4].get('total', 0) + 1
    except:
        pass

# Get top 10 codes by total count
sorted_cpc = sorted(cpc_monthly_counts.items(), key=lambda x: x[1]['total'], reverse=True)[:10]
print('Top 10 CPC Level 4 codes by count:')
for i, (code, data) in enumerate(sorted_cpc, 1):
    print(f"{i}. {code}: {data['total']} filings")

top_codes = [code for code, _ in sorted_cpc]
print('__RESULT__:')
print(json.dumps(top_codes))

